from dataclasses import dataclass, field
from enum import Enum

class GoalStatus(Enum):
    PENDING   = "pending"
    ACTIVE    = "active"
    COMPLETE  = "complete"
    FAILED    = "failed"
    BLOCKED   = "blocked"   # waiting on another sub-goal

@dataclass
class Goal:
    description: str
    success_criterion: str               # machine-checkable definition of done
    hard_constraints: list[str] = field(default_factory=list)
    soft_preferences: list[str] = field(default_factory=list)
    sub_goals: list["Goal"] = field(default_factory=list)
    status: GoalStatus = GoalStatus.PENDING
    result: str | None = None

    def is_done(self) -> bool:
        return self.status in (GoalStatus.COMPLETE, GoalStatus.FAILED)

    def all_sub_goals_done(self) -> bool:
        return all(sg.is_done() for sg in self.sub_goals)

    def to_prompt_block(self) -> str:
        """Render goal context for injection into a prompt."""
        lines = [
            f"Goal: {self.description}",
            f"Done when: {self.success_criterion}",
        ]
        if self.hard_constraints:
            lines.append("Hard constraints (must not violate):")
            lines.extend(f"  - {c}" for c in self.hard_constraints)
        if self.soft_preferences:
            lines.append("Soft preferences (apply where possible):")
            lines.extend(f"  - {p}" for p in self.soft_preferences)
        pending = [sg for sg in self.sub_goals if sg.status == GoalStatus.PENDING]
        if pending:
            lines.append(f"Remaining sub-goals: {len(pending)}")
        return "\n".join(lines)

# Build a goal for a booking task
booking_goal = Goal(
    description="Book cheapest round-trip NYC-Paris, June 10-17",
    success_criterion="booking_id is returned and ticket is confirmed",
    hard_constraints=["Refundable 24h", "No Spirit Airlines"],
    soft_preferences=["Direct flight", "Morning departure"],
    sub_goals=[
        Goal(
            description="Search available flights",
            success_criterion="flight list returned with prices",
        ),
        Goal(
            description="Select cheapest valid option",
            success_criterion="flight selected that satisfies all hard constraints",
        ),
        Goal(
            description="Complete booking",
            success_criterion="booking_id returned",
        ),
    ],
)

print(booking_goal.to_prompt_block())

import anthropic
import json

client = anthropic.Anthropic()

# Pattern 3: structured output via task_complete tool
TOOLS = [
    {
        "name": "search_flights",
        "description": "Search available flights between two cities.",
        "input_schema": {
            "type": "object",
            "properties": {
                "origin": {"type": "string"},
                "destination": {"type": "string"},
                "date": {"type": "string", "description": "ISO 8601 date"},
            },
            "required": ["origin", "destination", "date"],
        },
    },
    {
        "name": "task_complete",
        "description": "Call this exactly once when the goal is fully achieved.",
        "input_schema": {
            "type": "object",
            "properties": {
                "booking_id":    {"type": "string"},
                "airline":       {"type": "string"},
                "total_price":   {"type": "number"},
                "departure_time":{"type": "string"},
            },
            "required": ["booking_id", "airline", "total_price", "departure_time"],
        },
    },
]

resp = client.messages.create(
    model="claude-haiku-4-5-20251001",
    max_tokens=512,
    system=(
        "Book the cheapest flight from NYC to Paris on June 10. "
        "Call task_complete with the result when done."
    ),
    messages=[{"role": "user", "content": "Proceed."}],
    tools=TOOLS,
)

for block in resp.content:
    if block.type == "tool_use" and block.name == "task_complete":
        result = block.input
        print(f"Goal complete: booking_id={result['booking_id']}, "
              f"price=${result['total_price']:.2f}")
